SELECT id, tenant_id, api_config_id, call_direction, caller_ip, request_data, response_data, call_status, error_message, cost_time_ms, call_time, create_time, create_by, update_time, update_by FROM ${tableName} WHERE 1 = 1
AND api_config_id = #{apiConfigId}
AND call_direction = #{callDirection}
AND call_status = #{callStatus}
AND caller_ip LIKE CONCAT('%', #{callerIp}, '%')
AND call_time >= #{startTime}
AND call_time <= #{endTime}
ORDER BY call_time DESC, id DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(1)
FROM ${tableName}
WHERE 1 = 1

    AND api_config_id = #{apiConfigId}


    AND call_direction = #{callDirection}


    AND call_status = #{callStatus}


    AND caller_ip LIKE CONCAT('%', #{callerIp}, '%')


    AND call_time >= #{startTime}


    AND call_time <= #{endTime}
